INSERT INTO collections (id, collection_name, data, created_at, updated_at) VALUES ('p-001', 'products', '{"id":"p-001","slug":"maximus-sirius-led-h4-85w","name":"Maximus Sirius LED Ultra Bright Headlights H4 - 85W","sku":"MXS-LED-H4-85W","brand":"Maximus","brandSlug":"maximus","category":"LED & Lighting","categorySlug":"led-lighting","images":[{"id":"i1","url":"https://images.unsplash.com/photo-1558981806-ec527fa84c39?auto=format&fit=crop&w=600&h=600&q=80","alt":"LED H4 Headlight","isPrimary":true},{"id":"i2","url":"https://images.unsplash.com/photo-1604999974288-6e3329448cc1?auto=format&fit=crop&w=600&h=600&q=80","alt":"LED Headlight side view","isPrimary":false},{"id":"i3","url":"https://images.unsplash.com/photo-1519681393784-d120267933ba?auto=format&fit=crop&w=600&h=600&q=80","alt":"LED installed on car","isPrimary":false}],"price":15000,"originalPrice":18000,"discount":17,"stock":45,"inStock":true,"rating":4.7,"reviewCount":23,"description":"Maximus Sirius series ultra-bright LED headlights deliver 8500 lumens per pair. Compatible with projector and reflector housings. CANBUS compatible with anti-flicker design. Easy plug-and-play installation for most vehicles.","shortDescription":"85W ultra-bright LED headlight pair, H4 base, 8500 lumens, CANBUS compatible","specifications":[{"label":"Wattage","value":"85W"},{"label":"Lumens","value":"8500 lm/pair"},{"label":"Color Temp","value":"6500K White"},{"label":"Base","value":"H4"},{"label":"Cooling","value":"Turbo Fan + Heatsink"},{"label":"Warranty","value":"1 Year"},{"label":"CANBUS","value":"Compatible"},{"label":"IP Rating","value":"IP67 Waterproof"}],"vehicleCompatibility":[{"brand":"Toyota","model":"Corolla","yearFrom":2014,"yearTo":2026},{"brand":"Honda","model":"Civic","yearFrom":2016,"yearTo":2022},{"brand":"Suzuki","model":"Swift","yearFrom":2010,"yearTo":2024},{"brand":"Hyundai","model":"Elantra","yearFrom":2013,"yearTo":2022}],"installationAvailable":true,"installationPrice":1500,"warranty":"1 Year Manufacturer Warranty","tags":["led","headlight","h4","maximus","lighting"],"isFeatured":true,"isNew":false,"isBestSeller":true,"isFlashSale":false,"createdAt":"2024-01-15T00:00:00Z","updatedAt":"2026-06-01T00:00:00Z"}', '2024-01-15 00:00:00', '2024-01-15 00:00:00');
