:2014,"yearTo":2026},{"brand":"Honda","model":"Civic","yearFrom":2016,"yearTo":2022},{"brand":"Suzuki","model":"Swift","yearFrom":2010,"yearTo":2024},{"brand":"Hyundai","model":"Elantra","yearFrom":2013,"yearTo":2022}],"installationAvailable":true,"installationPrice":1500,"warranty":"1 Year Manufacturer Warranty","tags":["led","headlight","h4","maximus","lighting"],"isFeatured":true,"isNew":false,"isBestSeller":true,"isFlashSale":false,"createdAt":"2024-01-15T00:00:00Z","updatedAt":"2026-06-01T00:00:00Z"}', '2024-01-15 00:00:00', '2026-06-01 00:00:00');
INSERT INTO products (id, slug, sku, name, brand_slug, category_slug, price, original_price, stock, in_stock, rating, review_count, is_featured, is_new, is_best_seller, is_flash_sale, data, created_at, updated_at) VALUES ('p-002', 'maximus-intense-led-h4-30w', 'MXI-LED-H4-30W', 'Maximus Intense LED Headlight Bulb H4 - 30W Fanless', 'maximus', 'led-lighting', 5000, 6500, 78, 1, 4.5, 18, 0, 0, 1, 1, '{"id":"p-002","slug":"maximus-intense-led-h4-30w","name":"Maximus Intense LED Headlight Bulb H4 - 30W Fanless","sku":"MXI-LED-H4-30W","brand":"Maximus","brandSlug":"maximus","category":"LED & Lighting","categorySlug":"led-lighting","images":[{"id":"i1","url":"https://images.unsplash.com/photo-1580273916550-e323be2ae537?auto=format&fit=crop&w=600&h=600&q=80","alt":"LED H4 30W bulb","isPrimary":true},{"id":"i2","url":"https://images.unsplash.com/photo-1558981359-219d6364c9c8?auto=format&fit=crop&w=600&h=600&q=80","alt":"LED light installed","isPrimary":false}],"price":5000,"originalPrice":6500,"discount":23,"stock":78,"inStock":true,"rating":4.5,"reviewCount":18,"description":"Entry-level Intense series LED bulb. Compact fanless design means zero noise. Plug and play installation with no modification required.","shortDescription":"30W compact fanless LED headlight, H4 base, silent, plug & play","specifications":[{"label":"Wattage","value":"30W"},{"label":"Lumens","value":"4500 lm/pair"},{"label":"Color Temp","value":"6000K"},{"label":"Base","value":"H4"},{"label":"Design","value":"Fanless / Silent"}],"installationAvailable":true,"installationPrice":1000,"tags":["led","headlight","h4","fanless"],"isFeatured":false,"isNew":false,"isBestSeller":true,"isFlashSale":true,"flashSaleEnds":"2026-07-20T23:59:59Z","createdAt":"2024-03-10T00:00:00Z","updatedAt":"2026-07-01T00:00:00Z"}', '2024-03-10 00:00:00', '2026-07-01 00:00:00');
