INSERT INTO services (id, slug, type, name, price_from, data) VALUES ('svc-1', 'paint-protection-film', 'ppf', 'Paint Protection Film (PPF)', 25000, '{"id":"svc-1","slug":"paint-protection-film","type":"ppf","name":"Paint Protection Film (PPF)","description":"Professional PPF installation using premium self-healing TPU films. Choose from clear, matte, or colored PPF for full or partial coverage — applied in a dustfree studio.","image":"https://images.unsplash.com/photo-1607860108855-64acf2078ed9?auto=format&fit=crop&w=600&h=400&q=80","priceFrom":25000,"priceTo":150000,"duration":"1-2 Days","features":["Self-Healing TPU","UV Resistant","10 Year Warranty","Dustfree Studio","Free Pre-Inspection"],"popular":true}');
INSERT INTO services (id, slug, type, name, price_from, data) VALUES ('svc-2', 'ceramic-coating', 'ceramic', 'Ceramic Coating', 18000, '{"id":"svc-2","slug":"ceramic-coating","type":"ceramic","name":"Ceramic Coating","description":"Nano-ceramic coating that permanently bonds with your paint for superior gloss, hydrophobic protection, and UV resistance. Applied by certified technicians.","image":"https://images.unsplash.com/photo-1607860108855-64acf2078ed9?auto=format&fit=crop&w=600&h=400&q=80","priceFrom":18000,"priceTo":75000,"duration":"2-3 Days","features":["9H Hardness","Hydrophobic Effect","UV Protection","3-5 Year Life","Mirror Gloss Finish"],"popular":true}');
INSERT INTO services (id, slug, type, name, price_from, data) VALUES ('svc-3', 'car-detailing', 'detailing', 'Car Detailing', 5000, '{"id":"svc-3","slug":"car-detailing","type":"detailing","name":"Car Detailing","description":"Complete interior and exterior detailing. Paint correction, deep clean, clay bar treatment, wax, and full protection for a showroom-fresh finish.","image":"https://images.unsplash.com/photo-1596838132731-3301c3fd4317?auto=format&fit=crop&w=600&h=400&q=80","priceFrom":5000,"priceTo":35000,"duration":"4-8 Hours","features":["Paint Correction","Deep Interior Clean","Engine Bay Wash","Odor Removal","Machine Polishing"],"popular":false}');
INSERT INTO services (id, slug, type, name, price_from, data) VALUES ('svc-4', 'window-tint', 'tint', 'Window Tinting', 8000, '{"id":"svc-4","slug":"window-tint","type":"tint","name":"Window Tinting","description":"Premium Maximus nano-ceramic window tints with up to 99% UV rejection and superior heat blocking. 12 shades available, legally compliant options included.","image":"https://images.unsplash.com/photo-1544636331-9849c66b2a09?auto=format&fit=crop&w=600&h=400&q=80","priceFrom":8000,"priceTo":35000,"duration":"3-5 Hours","features":["99% UV Rejection","Heat Rejection","12 Shades","Anti-Scratch Coat","3 Year Warranty"],"popular":true}');
INSERT INTO services (id, slug, type, name, price_from, data) VALUES ('svc-5', 'installation', 'installation', 'Product Installation', 500, '{"id":"svc-5","slug":"installation","type":"installation","name":"Product Installation","description":"Professional installation of any car accessory — Android panels, reverse cameras, LED lights, dash cams, body kits, and more by certified auto technicians.","image":"https://images.unsplash.com/photo-1596838132731-3301c3fd4317?auto=format&fit=crop&w=600&h=400&q=80","priceFrom":500,"priceTo":15000,"duration":"1-4 Hours","features":["Certified Technicians","All Accessories","Clean Wire Management","Testing Included","1 Month Warranty"],"popular":false}');
