INSERT INTO blog_posts (id, slug, title, is_featured, published_at, data) VALUES ('b-001', 'ppf-vs-ceramic-coating-2026', 'PPF vs Ceramic Coating in Pakistan: Which One Protects Your Car?', 1, '2026-06-15 00:00:00', '{"id":"b-001","slug":"ppf-vs-ceramic-coating-2026","title":"PPF vs Ceramic Coating in Pakistan: Which One Protects Your Car?","excerpt":"Every car owner in Pakistan faces the same question: should I get Paint Protection Film (PPF) or ceramic coating? We break down the differences, costs, and which is right for your vehicle.","content":"","coverImage":"https://images.unsplash.com/photo-1607860108855-64acf2078ed9?auto=format&fit=crop&w=800&h=450&q=80","author":"Saad Sehgal","authorAvatar":"","category":"Guides","tags":["PPF","Ceramic","Protection"],"readTime":8,"viewCount":12450,"publishedAt":"2026-06-15T00:00:00Z","isFeatured":true}');
INSERT INTO blog_posts (id, slug, title, is_featured, published_at, data) VALUES ('b-002', 'best-android-panel-pakistan-2026', 'Best Android Panel in Pakistan 2026 – Smart Infotainment Upgrade Guide', 1, '2026-06-10 00:00:00', '{"id":"b-002","slug":"best-android-panel-pakistan-2026","title":"Best Android Panel in Pakistan 2026 – Smart Infotainment Upgrade Guide","excerpt":"Upgrading your car''s infotainment system? Here''s our comprehensive guide to the best Android panels available in Pakistan for every budget.","content":"","coverImage":"https://images.unsplash.com/photo-1503376780353-7e6692767b70?auto=format&fit=crop&w=800&h=450&q=80","author":"Team Shahzad Poshish House","authorAvatar":"","category":"Reviews","tags":["Android Panel","Multimedia","Tech"],"readTime":6,"viewCount":8920,"publishedAt":"2026-06-10T00:00:00Z","isFeatured":true}');
